Use ASP.NET Core's `WebApplicationFactory<Program>` — it hosts your server in-memory (no real HTTP listener) and lets you send raw MCP JSON-RPC requests:

### 1. Expose `Program` to your test project

In your server's `.csproj`:
```xml
<InternalsVisibleTo Include="YourServer.Tests" />
```
Or add to `Program.cs`:
```csharp
public partial class Program { }
```

### 2. Set up the test project

```bash
dotnet new xunit -n YourServer.Tests
cd YourServer.Tests
dotnet add reference ../YourServer/YourServer.csproj
dotnet add package Microsoft.AspNetCore.Mvc.Testing
```

### 3. Write tests

```csharp
using Microsoft.AspNetCore.Mvc.Testing;

public class HttpServerTests : IClassFixture<WebApplicationFactory<Program>>
{
    private readonly WebApplicationFactory<Program> _factory;

    public HttpServerTests(WebApplicationFactory<Program> factory)
        => _factory = factory;

    [Fact]
    public async Task McpEndpoint_AcceptsInitialize()
    {
        var client = _factory.CreateClient();
        var request = new
        {
            jsonrpc = "2.0", id = 1, method = "initialize",
            @params = new
            {
                protocolVersion = "2024-11-05",
                capabilities = new { },
                clientInfo = new { name = "test", version = "1.0" }
            }
        };

        var response = await client.PostAsJsonAsync("/mcp", request);
        response.EnsureSuccessStatusCode();
    }

    [Fact]
    public async Task McpEndpoint_InvokesTool()
    {
        var client = _factory.CreateClient();

        // Initialize session first
        var init = new
        {
            jsonrpc = "2.0", id = 1, method = "initialize",
            @params = new
            {
                protocolVersion = "2024-11-05",
                capabilities = new { },
                clientInfo = new { name = "test", version = "1.0" }
            }
        };
        await client.PostAsJsonAsync("/mcp", init);

        // Call a tool
        var toolCall = new
        {
            jsonrpc = "2.0", id = 2, method = "tools/call",
            @params = new { name = "echo", arguments = new { message = "hello" } }
        };

        var response = await client.PostAsJsonAsync("/mcp", toolCall);
        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadAsStringAsync();
        Assert.Contains("hello", body);
    }
}
```

**Key points:**
- `WebApplicationFactory` spins up your full ASP.NET Core pipeline in-memory — no ports, no network
- You must **initialize** the MCP session before calling tools (JSON-RPC protocol requirement)
- Adjust `/mcp` to match your `MapMcp()` route
- You can override services via `_factory.WithWebHostBuilder(b => b.ConfigureServices(...))` to inject fakes
